import { Company } from './../apis/models/company-list';
import { Project } from '../apis/models/project-list';
import { WorkHistoryModel } from './../apis/models/work-history';
import { ActionTypes } from "./actionTypes"

export const getWorkHistory = () => {
    return {
        type: ActionTypes.GET_WORK_HISTORY
    }
}
export const workHistoryReceived = (payload: WorkHistoryModel[]) => {
    return {
        type: ActionTypes.WORK_HISTORY_RECEIVED,
        payload
    }
}

export const getProjects = () => {
    return {
        type: ActionTypes.GET_PROJECTS
    }
}
export const projectsReceived = (payload: Project[]) => {
    return {
        type: ActionTypes.PROJECTS_RECEIVED,
        payload
    }
}

export const getCompanies = () => {
    return {
        type: ActionTypes.GET_COMPANIES
    }
}
export const companiesReceived = (payload: Company[]) => {
    return {
        type: ActionTypes.COMPANIES_RECEIVED,
        payload
    }
}