import { call, put, takeLatest } from "@redux-saga/core/effects";
import { ActionTypes } from '../actions/actionTypes';
import { ActionMain } from '../actions';
import { ApiRequests } from '../apis/requests';

export function* watcherMain() {
    yield takeLatest(ActionTypes.GET_WORK_HISTORY, workerGetWorkHistory);
    yield takeLatest(ActionTypes.GET_PROJECTS, workerGetProjects);
    yield takeLatest(ActionTypes.GET_COMPANIES, workerGetCompanies);
}


function* workerGetWorkHistory(action: any): any {
    let response = yield call(ApiRequests.getWorkHistorys);
    yield put(ActionMain.workHistoryReceived(response));
}

function* workerGetProjects(action: any): any {
    const response = yield call(ApiRequests.getProjectList)
    yield put(ActionMain.projectsReceived(response));
}

function* workerGetCompanies(action: any): any {
    const response = yield call(ApiRequests.getCompanyList);
    yield put(ActionMain.companiesReceived(response));
}